// modules/auth/lib/queries.ts
import { query } from '../db';
import { User, AuthError } from '../types';

export async function createUser(email: string, passwordHash: string): Promise<Result<User, AuthError>> {
  try {
    const result = await query<{ id: number }>('INSERT INTO users (email, password_hash) VALUES ($1, $2) RETURNING id', [email, passwordHash]);
    if (result.rows.length === 0) {
      return err({ code: 'USER_CREATE_FAILED', message: 'Failed to create user' });
    }
    const userId = result.rows[0].id;
    return ok({ id: userId, email, password_hash: passwordHash } as User);
  } catch (error) {
    return err({ code: 'DATABASE_ERROR', message: 'Database error occurred' });
  }
}

// modules/auth/routes/register.ts
import { Request, Response } from 'bun';
import { createUser } from '../lib/queries';
import { parseBody, ok, err, Result } from '../../../lib/result';

export async function registerHandler(req: Request): Promise<Response> {
  try {
    const body = await parseBody<{ email: string; password: string }>(req);
    if (!body.email || !body.password) {
      return err({ code: 'INVALID_REQUEST', message: 'Email and password are required' });
    }

    // Validate email format (simplified example)
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(body.email)) {
      return err({ code: 'INVALID_EMAIL', message: 'Invalid email format' });
    }

    // Hash password (simplified example)
    const passwordHash = body.password; // In a real app, use a secure hashing library

    const result = await createUser(body.email, passwordHash);
    if (result.isErr()) {
      return err(result.error);
    }

    return ok({ id: result.value.id }, 201);
  } catch (error) {
    return err({ code: 'INTERNAL_ERROR', message: 'Internal server error' });
  }
}

// modules/auth/module.contract.ts
import { defineContract } from 'aether';

export default defineContract({
  name: 'auth',
  description: 'Handles user authentication, session management, and authorization utilities.',

  dependencies: { modules: [] },

  exposes: {
    routes: [
      { method: 'POST', path: '/auth/login',   auth: false },
      { method: 'POST', path: '/auth/logout',  auth: true },
      { method: 'GET',  path: '/auth/session', auth: true },
      { method: 'POST', path: '/auth/register', auth: false }, // New route for user registration
    ],
    functions: ['requireUser', 'getSession', 'createSession', 'invalidateSession'],
    types: ['User', 'Session', 'AuthError'],
  },

  sideEffects: [
    'writes to: sessions table',
    'reads from: users table',
  ],

  invariants: [
    'A session must always be bound to exactly one user',
    'Expired sessions must never be returned as valid',
    'Logout must invalidate the session immediately',
  ],
});

